// Helper to extract values (0, 1, 2...)
type NumericValues<T> = {
    [K in keyof T]: T[K] extends number ? T[K] : never
}[keyof T];

// PUBLIC TYPES
export type ButtonInput = keyof typeof mappings.aliases | NumericValues<typeof mappings>; 
export type AxisInput = typeof mappings.axisAliases[number];
export type GamepadInput = ButtonInput | AxisInput;

// INTERNAL TYPES
export type InternalAction = number | AxisInput;

export default mappings;
